    12|
    13|const LEVEL_BADGES: Record<string, { label: string; dot: string }> = {
    14|  principiante: { label: 'Principiante', dot: 'bg-green-500' },
    15|  intermedio: { label: 'Intermedio', dot: 'bg-yellow-500' },
    16|  avanzado: { label: 'Avanzado', dot: 'bg-red-500' },
