    19|interface ProductCardProps {
    20|  product: {
    21|    id: string;
    22|    name: string;
    23|    slug: string;
    24|    price: number;
    25|    compare_at_price: number | null;
    26|    is_featured: boolean;
    27|    experience_level?: string | null;
    28|    images?: string[] | null;
    29|    image_url?: string | null;
    30|    category_slug?: string;
    31|    stock?: number;
    32|  };
    33|}
    34|
    35|export function ProductCard({ product }: ProductCardProps) {
    36|  const addItem = useCartStore((s) => s.addItem);
    37|  const productImage = product.images?.[0] || product.image_url || PRODUCT_PLACEHOLDERS[product.category_slug || 'default'] || DEFAULT_PRODUCT_IMAGE;
    38|  const level = product.experience_level
