    40|    : null;
    41|  const hasDiscount = product.compare_at_price && product.compare_at_price > product.price;
    42|  const discountPct = hasDiscount
    43|    ? Math.round(((product.compare_at_price! - product.price) / product.compare_at_price!) * 100)
    44|    : 0;
    45|
    46|  function handleAddToCart(e: React.MouseEvent) {
    47|    e.preventDefault();
    48|    e.stopPropagation();
    49|    addItem({
    50|      id: product.id,
    51|      name: product.name,
    52|      price: product.price,
    53|      image_url: productImage,
    54|      max_stock: product.stock,
    55|    });
