    20|    .eq('slug', slug)
    21|    .single();
    22|
    23|  if (!category) return { title: 'Categoría no encontrada' };
    24|  const cat = category as unknown as { name: string; description: string | null };
    25|
    26|  const description = cat.description || `Explora nuestra coleccion de ${cat.name} en Fun4Me Store. Envio discreto en todo Paraguay.`;
    27|
    28|  return {
    29|    title: cat.name,
    30|    description,
    31|    openGraph: {
