    38|
    39|export default async function CategoryPage({ params, searchParams }: Props) {
    40|  const { slug } = await params;
    41|  const sp = await searchParams;
    42|  const supabase = await createClient();
    43|
    44|  const { data: category } = await supabase
    45|    .from('categories')
    46|    .select('*')
    47|    .eq('slug', slug)
    48|    .single();
    49|
    50|  if (!category) notFound();
    51|  const cat = category as unknown as ExtendedCategory;
    52|
    53|  let query = supabase
    54|    .from('products')
    55|    .select('*, categories(slug)')
    56|    .eq('category_id', cat.id)
    57|    .eq('is_active', true);
    58|
    59|  if (sp.level) {
    60|    query = query.eq('experience_level' as string, sp.level);
    61|  }
    62|  if (sp.min) {
    63|    query = query.gte('price', parseInt(sp.min));
    64|  }
    65|  if (sp.max) {
    66|    query = query.lte('price', parseInt(sp.max));
    67|  }
    68|
    69|  switch (sp.sort) {
    70|    case 'price_asc':
    71|      query = query.order('price', { ascending: true });
    72|      break;
    73|    case 'price_desc':
    74|      query = query.order('price', { ascending: false });
    75|      break;
    76|    case 'newest':
    77|      query = query.order('created_at', { ascending: false });
    78|      break;
    79|    default:
    80|      query = query.order('is_featured', { ascending: false }).order('created_at', { ascending: false });
    81|  }
    82|
    83|  const { data: products } = await query;
    84|  const items = (products || []) as unknown as (ExtendedProduct & { categories: { slug: string } | null })[];
    85|
