{"path": "/root/fun4me-store/src/components/store/search-autocomplete.tsx", "content": "'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import { useRouter } from 'next/navigation';
import Image from 'next/image';
import Link from 'next/link';
import { Input } from '@/components/ui/input';
import { Search } from 'lucide-react';
import { createClient } from '@/lib/supabase/client';
import { formatPrice } from '@/lib/utils/format';
import { DEFAULT_PRODUCT_IMAGE } from '@/lib/images';

interface Suggestion {
  id: string;
  name: string;
  slug: string;
  price: number;
  images: string[] | null;
}

interface SearchAutocompleteProps {
  onNavigate?: () => void;
  className?: string;
}

export function SearchAutocomplete({ onNavigate, className }: SearchAutocompleteProps) {
  const router = useRouter();
  const [query, setQuery] = useState('');
  const [suggestions, setSuggestions] = useState<Suggestion[]>([]);
  const [showDropdown, setShowDropdown] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);
  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

  const fetchSuggestions = useCallback(async (searchTerm: string) => {
    if (!searchTerm.trim()) {
      setSuggestions([]);
      setShowDropdown(false);
      return;
    }

    setIsLoading(true);
    try {
      const supabase = createClient();
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      const { data } = await (supabase as any)
        .from('products')
        .select('id, name, slug, price, images')
        .eq('is_active', true)
        .ilike('name', `%${searchTerm}%`)
        .limit(6);

      const results = (data || []) as Suggestion[];
      setSuggestions(results);
      setShowDropdown(results.length > 0);
    } catch {
      setSuggestions([]);
    } finally {
      setIsLoading(false);
    }
  }, []);

  useEffect(() => {
    if (debounceRef.current) {
      clearTimeout(debounceRef.current);
    }

    debounceRef.current = setTimeout(() => {
      fetchSuggestions(query);
    }, 300);

    return () => {
      if (debounceRef.current) {
        clearTimeout(debounceRef.current);
      }
    };
  }, [query, fetchSuggestions]);

  // Close dropdown on outside click
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (containerRef.current && !containerRef.current.contains(e.target as Node)) {
        setShowDropdown(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    if (query.trim()) {
      router.push(`/buscar?q=${encodeURIComponent(query.trim())}`);
      setQuery('');
      setShowDropdown(false);
      setSuggestions([]);
      onNavigate?.();
    }
  }

  function handleSuggestionClick() {
    setQuery('');
    setShowDropdown(false);
    setSuggestions([]);
    onNavigate?.();
  }

  return (
    <div ref={containerRef} className={`relative ${className || ''}`}>
      <form onSubmit={handleSubmit}>
        <div className="relative w-full">
          <Search className="absolute left-2.5 top-1/2 h-4 w-4 -translate-y-1/2 text-muted-foreground" />
          <Input
            type="search"
            placeholder="Buscar productos..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            onFocus={() => {
              if (suggestions.length > 0) setShowDropdown(true);
            }}
            className="pl-8"
          />
        </div>
      </form>

      {showDropdown && (
        <div className="absolute left-0 top-full z-50 mt-1 w-full rounded-lg border bg-popover shadow-lg">
          {isLoading ? (
            <div className="px-4 py-3 text-sm text-muted-foreground">Buscando...</div>
          ) : (
            suggestions.map((s) => (
              <Link
                key={s.id}
                href={`/producto/${s.slug}`}
                onClick={handleSuggestionClick}
                className="flex items-center gap-3 px-3 py-2 transition-colors hover:bg-muted first:rounded-t-lg last:rounded-b-lg"
              >
                <div className="relative h-10 w-10 shrink-0 overflow-hidden rounded-md">
                  <Image
                    src={s.images?.[0] || DEFAULT_PRODUCT_IMAGE}
                    alt={s.name}
                    fill
                    className="object-cover"
                  />
                </div>
                <div className="min-w-0 flex-1">
                  <p className="truncate text-sm font-medium">{s.name}</p>
                  <p className="text-xs font-semibold text-rose-600">{formatPrice(s.price)}</p>
                </div>
              </Link>
            ))
          )}
        </div>
      )}
    </div>
  );
}
"}

{"path": "/root/fun4me-store/src/components/store/pagination.tsx", "content": "'use client';

import Link from 'next/link';
import { usePathname, useSearchParams } from 'next/navigation';
import { ChevronLeft, ChevronRight } from 'lucide-react';
import { Button } from '@/components/ui/button';

interface PaginationProps {
  currentPage: number;
  totalPages: number;
  totalItems: number;
  pageSize: number;
}

export function Pagination({ currentPage, totalPages, totalItems, pageSize }: PaginationProps) {
  const pathname = usePathname();
  const searchParams = useSearchParams();

  if (totalPages <= 1) return null;

  function buildHref(page: number) {
    const params = new URLSearchParams(searchParams.toString());
    if (page <= 1) {
      params.delete('page');
    } else {
      params.set('page', String(page));
    }
    const qs = params.toString();
    return `${pathname}${qs ? `?${qs}` : ''}`;
  }

  const from = (currentPage - 1) * pageSize + 1;
  const to = Math.min(currentPage * pageSize, totalItems);

  // Build page numbers to show
  const pages: (number | '...')[] = [];
  if (totalPages <= 7) {
    for (let i = 1; i <= totalPages; i++) pages.push(i);
  } else {
    pages.push(1);
    if (currentPage > 3) pages.push('...');
    const start = Math.max(2, currentPage - 1);
    const end = Math.min(totalPages - 1, currentPage + 1);
    for (let i = start; i <= end; i++) pages.push(i);
    if (currentPage < totalPages - 2) pages.push('...');
    pages.push(totalPages);
  }

  return (
    <div className="mt-8 space-y-4">
      <p className="text-center text-sm text-muted-foreground">
        Mostrando {from}-{to} de {totalItems} productos
      </p>
      <div className="flex items-center justify-center gap-1">
        {currentPage > 1 ? (
          <Link href={buildHref(currentPage - 1)}>
            <Button variant="outline" size="sm" className="gap-1">
              <ChevronLeft className="h-4 w-4" /> Anterior
            </Button>
          </Link>
        ) : (
          <Button variant="outline" size="sm" className="gap-1" disabled>
            <ChevronLeft className="h-4 w-4" /> Anterior
          </Button>
        )}

        {pages.map((page, idx) =>
          page === '...' ? (
            <span key={`ellipsis-${idx}`} className="px-2 text-muted-foreground">
              ...
            </span>
          ) : (
            <Link key={page} href={buildHref(page)}>
              <Button
                variant={page === currentPage ? 'default' : 'outline'}
                size="sm"
                className={page === currentPage ? 'bg-rose-500 text-white hover:bg-rose-600' : ''}
              >
                {page}
              </Button>
            </Link>
          )
        )}

        {currentPage < totalPages ? (
          <Link href={buildHref(currentPage + 1)}>
            <Button variant="outline" size="sm" className="gap-1">
              Siguiente <ChevronRight className="h-4 w-4" />
            </Button>
          </Link>
        ) : (
          <Button variant="outline" size="sm" className="gap-1" disabled>
