                      category_slug: product.categories?.slug || slug,
                    }}
                  />
                ))}
              </div>
              <Pagination
                currentPage={safePage}
                totalPages={totalPages}
                totalItems={total}
                pageSize={PAGE_SIZE}
              />
            </>
